import { Routes } from "@angular/router";


export const Masterroutes: Routes = [
    {
        path: '',
        loadComponent: () => import('./master-tabs.component').then(masterTabs => masterTabs.MasterTabsComponent),
        data: { breadcrumb: 'master/master-tabs' },
        children: [
            {
                path: 'client',
                loadComponent: () => import('../client/client.component').then(client => client.ClientComponent),
                data: { breadcrumb: 'Client' },
            },
            {
                path: 'country',
                loadComponent: () => import('../country/country.component').then(country => country.CountryComponent),
                data: { breadcrumb: 'Country' },
            },
            {
                path: 'vessel',
                loadComponent: () => import('../vessel/vessel.component').then(vessel => vessel.VesselComponent),
                data: { breadcrumb: 'Vessel' },
            },
            {
                path: 'cargo',
                loadComponent: () => import('../cargo/cargo.component').then(cargo => cargo.CargoComponent),
                data: { breadcrumb: 'Cargo' },
            },
            {
                path: 'purpose',
                loadComponent: () => import('../purpose/purpose.component').then(purpose => purpose.PurposeComponent),
                data: { breadcrumb: 'Purpose' },
            },
            {
                path: 'port-agent',
                loadComponent: () => import('../port-agent/port-agent.component').then(agent => agent.PortAgentComponent),
                data: { breadcrumb: 'Port Agent' },
            },
            {
                path: 'port',
                loadComponent: () => import('../port/port.component').then(port => port.PortComponent),
                data: { breadcrumb: 'Port' },
            },
            {
                path: 'user-management',
                loadComponent: () => import('../user-management/user-management.component').then(user => user.UserManagementComponent),
                data: { breadcrumb: 'User Management' },
            },
            {
                path: 'tariff-services',
                loadComponent: () => import('../tariff-services/tariff-services.component').then(tariff => tariff.TariffServicesComponent),
                data: { breadcrumb: 'Tariff Services' },
            }

        ]
    }
];
